     1→import { Device, DeviceCapabilities } from './Device.js';
     2→import type { PrecisionClock } from '@psyforge/timing';
     3→
     4→export interface AudioDeviceInfo {
     5→  deviceId: string;
     6→  label: string;
     7→  kind: MediaDeviceKind;
     8→  groupId: string;
     9→}
    10→
    11→export interface AudioEventData {
    12→  level?: number;
    13→  frequency?: number;
    14→  duration?: number;
    15→  buffer?: ArrayBuffer;
    16→}
    17→
    18→export class AudioDevice extends Device {
    19→  private audioContext?: AudioContext;
    20→  private mediaStream?: MediaStream;
    21→  private analyser?: AnalyserNode;
    22→  private microphone?: MediaStreamAudioSourceNode;
    23→  private outputNode?: AudioDestinationNode;
    24→  private isRecording: boolean = false;
    25→
    26→  constructor(clock: PrecisionClock) {
    27→    const capabilities: DeviceCapabilities = {
    28→      canDetectHotplug: true,
    29→      supportsHighPrecisionTiming: true,
    30→      maxSampleRate: 48000,
    31→      supportedFormats: ['audio/wav', 'audio/webm', 'audio/ogg'],
    32→    };
    33→
    34→    super('audio-primary', 'audio', capabilities, clock);
    35→  }
    36→
    37→  async initialize(): Promise<void> {
    38→    if (this._isConnected) {
    39→      return;
    40→    }
    41→
    42→    try {
    43→      // Create audio context
    44→      this.audioContext = new (window.AudioContext ||
    45→        (window as any).webkitAudioContext)();
    46→
    47→      // Resume context if suspended (required for some browsers)
    48→      if (this.audioContext.state === 'suspended') {
    49→        await this.audioContext.resume();
    50→      }
    51→
    52→      this.outputNode = this.audioContext.destination;
    53→      this.setConnected(true);
    54→
    55→      // Monitor device changes
    56→      navigator.mediaDevices?.addEventListener(
    57→        'devicechange',
    58→        this.handleDeviceChange.bind(this),
    59→      );
    60→    } catch (error) {
    61→      throw new Error(`Failed to initialize audio device: ${error}`);
    62→    }
    63→  }
    64→
    65→  async cleanup(): Promise<void> {
    66→    await this.stopRecording();
    67→
    68→    if (this.mediaStream) {
    69→      this.mediaStream.getTracks().forEach((track) => track.stop());
    70→      this.mediaStream = undefined;
    71→    }
    72→
    73→    if (this.audioContext) {
    74→      await this.audioContext.close();
    75→      this.audioContext = undefined;
    76→    }
    77→
    78→    navigator.mediaDevices?.removeEventListener(
    79→      'devicechange',
    80→      this.handleDeviceChange.bind(this),
    81→    );
    82→
    83→    this.analyser = undefined;
    84→    this.microphone = undefined;
    85→    this.outputNode = undefined;
    86→
    87→    this.setConnected(false);
    88→  }
    89→
    90→  async detectCapabilities(): Promise<DeviceCapabilities> {
    91→    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
    92→      return {
    93→        canDetectHotplug: false,
    94→        supportsHighPrecisionTiming: false,
    95→        maxSampleRate: 0,
    96→        supportedFormats: [],
    97→      };
    98→    }
    99→
   100→    const devices = await this.getAudioDevices();
   101→    // TODO: Use hasInput/hasOutput for more specific capability detection
   102→    devices.some((d) => d.kind === 'audioinput');
   103→    devices.some((d) => d.kind === 'audiooutput');
   104→
   105→    return {
   106→      canDetectHotplug: true,
   107→      supportsHighPrecisionTiming: true,
   108→      maxSampleRate: this.audioContext?.sampleRate || 48000,
   109→      supportedFormats: ['audio/wav', 'audio/webm', 'audio/ogg'],
   110→    };
   111→  }
   112→
   113→  async getAudioDevices(): Promise<AudioDeviceInfo[]> {
   114→    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
   115→      return [];
   116→    }
   117→
   118→    try {
   119→      const devices = await navigator.mediaDevices.enumerateDevices();
   120→      return devices
   121→        .filter(
   122→          (device) =>
   123→            device.kind === 'audioinput' || device.kind === 'audiooutput',
   124→        )
   125→        .map((device) => ({
   126→          deviceId: device.deviceId,
   127→          label: device.label,
   128→          kind: device.kind,
   129→          groupId: device.groupId,
   130→        }));
   131→    } catch (error) {
   132→      console.error('Error enumerating audio devices:', error);
   133→      return [];
   134→    }
   135→  }
   136→
   137→  async startRecording(deviceId?: string): Promise<void> {
   138→    if (this.isRecording) {
   139→      return;
   140→    }
   141→
   142→    if (!this.audioContext) {
   143→      throw new Error('Audio context not initialized');
   144→    }
   145→
   146→    try {
   147→      const constraints: MediaStreamConstraints = {
   148→        audio: deviceId ? { deviceId: { exact: deviceId } } : true,
   149→      };
   150→
   151→      this.mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
   152→      this.microphone = this.audioContext.createMediaStreamSource(
   153→        this.mediaStream,
   154→      );
   155→
   156→      // Create analyser for audio level monitoring
   157→      this.analyser = this.audioContext.createAnalyser();
   158→      this.analyser.fftSize = 256;
   159→      this.microphone.connect(this.analyser);
   160→
   161→      this.isRecording = true;
   162→      this.emitEvent('recordingstarted', { started: true });
   163→
   164→      // Start monitoring audio levels
   165→      this.monitorAudioLevel();
   166→    } catch (error) {
   167→      throw new Error(`Failed to start recording: ${error}`);
   168→    }
   169→  }
   170→
   171→  async stopRecording(): Promise<void> {
   172→    if (!this.isRecording) {
   173→      return;
   174→    }
   175→
   176→    if (this.mediaStream) {
   177→      this.mediaStream.getTracks().forEach((track) => track.stop());
   178→    }
   179→
   180→    if (this.microphone) {
   181→      this.microphone.disconnect();
   182→    }
   183→
   184→    this.isRecording = false;
   185→    this.emitEvent('recordingstopped', { stopped: true });
   186→  }
   187→
   188→  async playSound(buffer: ArrayBuffer, volume: number = 1.0): Promise<void> {
   189→    if (!this.audioContext || !this.outputNode) {
   190→      throw new Error('Audio context not initialized');
   191→    }
   192→
   193→    try {
   194→      const audioBuffer = await this.audioContext.decodeAudioData(
   195→        buffer.slice(0),
   196→      );
   197→      const source = this.audioContext.createBufferSource();
   198→      const gainNode = this.audioContext.createGain();
   199→
   200→      source.buffer = audioBuffer;
   201→      gainNode.gain.value = Math.max(0, Math.min(1, volume));
   202→
   203→      source.connect(gainNode);
   204→      gainNode.connect(this.outputNode);
   205→
   206→      const startTime = this.audioContext.currentTime;
   207→      source.start(startTime);
   208→
   209→      this.emitEvent('soundplayed', {
   210→        duration: audioBuffer.duration,
   211→        startTime: this.clock.now(),
   212→      });
   213→    } catch (error) {
   214→      throw new Error(`Failed to play sound: ${error}`);
   215→    }
   216→  }
   217→
   218→  async createTone(
   219→    frequency: number,
   220→    duration: number,
   221→    volume: number = 0.5,
   222→  ): Promise<void> {
   223→    if (!this.audioContext || !this.outputNode) {
   224→      throw new Error('Audio context not initialized');
   225→    }
   226→
   227→    const oscillator = this.audioContext.createOscillator();
